import React from "react";

const HistoryPanel = ({ history, onLoadEntry, onClose, onClearHistory }) => {
  const formatDate = (timestamp) => {
    return new Date(timestamp).toLocaleString();
  };

  const getRiskColor = (risk) => {
    return risk === "High" ? "#ef4444" : "#22c55e";
  };

  return (
    <div className="history-panel">
      <div className="history-header">
        <h3>📋 Analysis History</h3>
        <div className="history-actions">
          <button 
            className="clear-history-btn"
            onClick={onClearHistory}
            disabled={history.length === 0}
          >
            Clear All
          </button>
          <button className="close-history-btn" onClick={onClose}>
            ×
          </button>
        </div>
      </div>

      <div className="history-content">
        {history.length === 0 ? (
          <div className="empty-history">
            <p>No analysis history yet</p>
            <span>Your analyses will appear here</span>
          </div>
        ) : (
          <div className="history-list">
            {history.map((entry) => (
              <div key={entry.id} className="history-item">
                <div className="history-item-header">
                  <span className="history-type">{entry.type === "individual" ? "👤" : "📁"}</span>
                  <span className="history-timestamp">{formatDate(entry.timestamp)}</span>
                </div>

                <div className="history-summary">
                  {entry.type === "individual" ? (
                    <>
                      <div className="risk-badge" style={{ 
                        backgroundColor: getRiskColor(entry.summary.churnRisk) 
                      }}>
                        {entry.summary.churnRisk} Risk
                      </div>
                      <span className="probability">
                        {(entry.summary.probability * 100).toFixed(1)}%
                      </span>
                      <span className="customer-id">{entry.summary.customerId}</span>
                    </>
                  ) : (
                    <>
                      <span className="file-name">{entry.summary.fileName}</span>
                      <span className="batch-stats">
                        {entry.summary.totalProcessed} processed • {entry.summary.churnCount} churn
                      </span>
                    </>
                  )}
                </div>

                <button 
                  className="load-history-btn"
                  onClick={() => onLoadEntry(entry)}
                  title="Load this analysis"
                >
                  Load
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryPanel;
